/**
 * Bridge → bridge envelope forwarder.
 *
 * When an authenticated bridge sends `kind: 'outbound_envelope'` over its
 * WebSocket, the gateway must route that envelope to the recipient agent
 * (look up their tenant + dispatch as inbound). Without this, replies
 * generated by adapters that reach the bridge via the WS-only outbound
 * path are silently dropped.
 *
 * This is the same logical path POST /didcomm uses, but the recipient is
 * resolved from the envelope's `to[]` field instead of the Host header.
 */

import { agents, toTenantId, withTenant, type CloudDbClient } from '@kybernesis/arp-cloud-db';
import { eq } from 'drizzle-orm';
import { dispatchInbound, type DispatchContext, type PeerResolver } from './dispatch.js';
import type { PostgresAudit } from './audit.js';
import type { SessionRegistry } from './sessions.js';
import type { CloudRuntimeLogger, TenantMetrics, WsClientEvent } from './types.js';
import type { Pdp } from '@kybernesis/arp-pdp';

export interface ForwardOptions {
  db: CloudDbClient;
  sessions: SessionRegistry;
  pdp: Pdp;
  resolver: PeerResolver;
  logger: CloudRuntimeLogger;
  metrics: TenantMetrics;
  auditFactory: (tenantDbForAgent: ReturnType<typeof withTenant>) => PostgresAudit;
  now?: () => number;
}

export function createForwardOutboundEnvelope(opts: ForwardOptions) {
  const now = opts.now ?? (() => Date.now());
  return async function forwardOutbound(params: {
    tenantId: string;
    agentDid: string;
    event: Extract<WsClientEvent, { kind: 'outbound_envelope' }>;
  }): Promise<void> {
    const { event } = params;
    const log = opts.logger.child({
      senderTenantId: params.tenantId,
      senderAgentDid: params.agentDid,
      msgId: event.msgId,
    });
    if (!event.envelope || !event.peerDid) {
      log.warn({}, 'outbound_envelope_invalid');
      return;
    }
    // Look up recipient agent → recipient tenant.
    const rows = await opts.db
      .select({ tenantId: agents.tenantId, did: agents.did })
      .from(agents)
      .where(eq(agents.did, event.peerDid))
      .limit(1);
    const recipient = rows[0];
    if (!recipient) {
      log.warn({ peerDid: event.peerDid }, 'outbound_envelope_unknown_recipient');
      return;
    }
    const recipientTenantDb = withTenant(opts.db, toTenantId(recipient.tenantId));
    const ctx: DispatchContext = {
      tenantDb: recipientTenantDb,
      tenantId: recipient.tenantId,
      agentDid: recipient.did,
      audit: opts.auditFactory(recipientTenantDb),
      pdp: opts.pdp,
      resolver: opts.resolver,
      sessions: opts.sessions,
      logger: opts.logger,
      metrics: opts.metrics,
      now,
    };
    const result = await dispatchInbound(ctx, event.envelope);
    if (!result.ok) {
      log.warn({ reason: result.reason, recipient: recipient.did }, 'outbound_envelope_denied');
    }
  };
}
